#nullable enable // autogenerated

using MVZ2.GameContent.Models;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Models;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Models;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Modifiers;
using Tools;

namespace MVZ2.GameContent.Buffs.Enemies
{

    [AutoBuffDefinition(VanillaBuffNames.Enemy.gravelOnFace)]
    public class GravelOnFaceBuff : BuffDefinition
    {
        public GravelOnFaceBuff(string nsp, string name) : base(nsp, name)
        {
            AddModelInsertion(LogicModelHelper.ANCHOR_HEAD, VanillaModelKeys.gravelOnFace, VanillaModelID.gravelOnFace);
            AddModifier(new BooleanModifier(VanillaEntityProps.AI_FROZEN, true));
        }
        public override void OnCreate(Buff buff)
        {
            base.OnCreate(buff);
            SetTimer(buff, TimerHelper.NewSecondTimer(DEFAULT_SECONDS));
        }
        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff);
            var timer = GetTimer(buff);
            if (timer.RunToExpiredOrNull())
            {
                buff.Remove();
            }
            var entity = buff.GetEntity();
            if (entity != null && entity.IsDead)
            {
                buff.Remove();
            }
        }
        public static FrameTimer? GetTimer(Buff buff)
        {
            return buff.GetProperty<FrameTimer>(PROP_TIMER);
        }
        public static void SetTimer(Buff buff, FrameTimer? value)
        {
            buff.SetProperty(PROP_TIMER, value);
        }
        public static void ResetTime(Buff buff, int frames)
        {
            var timer = GetTimer(buff);
            if (timer == null)
                return;
            timer.ResetTime(frames);
        }
        public static void MaxTime(Buff buff, int frames)
        {
            var timer = GetTimer(buff);
            if (timer == null || timer.Frame >= frames)
                return;
            timer.ResetTime(frames);
        }
        public const float DEFAULT_SECONDS = 5f;
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("timer");
    }
}
